from math import isfinite

class Signal:
    def __init__(self):
        self._score = 0.0

    @property
    def score(self) -> float:
        return self._score

    @score.setter
    def score(self, value: float) -> None:
        v = float(value)
        if not isfinite(v) or not 0.0 <= v <= 1.0:
            raise ValueError("score fuera de rango")
        self._score = v

s = Signal()
s.score = 0.4
print("ok", s.score)
try:
    s.score = 1.5
except ValueError as e:
    print("reject", e)
try:
    s.score = float("nan")
except ValueError as e:
    print("reject_nan", e)
_j2_mark = 11

